                        acc = (acc * 16777619) & 0x7fffffff
                }
        }
        return fmt.Sprintf("%x", acc)
}

func cloneWorld(w *World) *World {
        size := w.Width * w.Height
        seen := append([]bool(nil), w.Seen...)
